import json, re

lines = open('ios_crash.ips').readlines()
raw_body = ''.join(lines[1:])
raw_body = re.sub(r'"vmregioninfo"', '"vmregioninfo_lower"', raw_body)
crash = json.loads(raw_body)

# Look for additional info fields
interesting_keys = ['asiBacktraces', 'lastExceptionBacktrace', 'asi', 'extMods',
                    'crashReporterKey', 'roots', 'vmSummary', 'legacyInfo',
                    'modelCode', 'isCorpse', 'captureTime']
print("=== Additional Crash Info ===")
for k in interesting_keys:
    if k in crash:
        val = crash[k]
        if isinstance(val, (str, int, float, bool)):
            print(f"  {k}: {val}")
        elif isinstance(val, dict):
            print(f"  {k}: {json.dumps(val)[:200]}")
        elif isinstance(val, list):
            print(f"  {k}: [{len(val)} items]")

# Check asiBacktraces for managed exception text
if 'asiBacktraces' in crash:
    print("\n=== ASI Backtraces ===")
    for bt in crash['asiBacktraces']:
        print(bt[:1000])

# Show the Objective-C exception / NSException info if present
if 'lastExceptionBacktrace' in crash:
    leb = crash['lastExceptionBacktrace']
    print(f"\n=== lastExceptionBacktrace: {len(leb)} frames ===")

# Check for userInfo/reason in other top-level keys
for k in crash:
    if k not in interesting_keys and k not in ['usedImages', 'threads', 'exception', 'termination', 'asi']:
        val = crash[k]
        if isinstance(val, (str,)) and len(val) > 10:
            print(f"\n  {k} (str): {val[:200]}")
        elif isinstance(val, dict) and len(str(val)) > 10:
            s = json.dumps(val)
            if len(s) > 20:
                print(f"\n  {k} (dict): {s[:200]}")

